const text = $json.message?.text || '';
const parts = text.trim().split(/\s+/);
const comando = (parts[0] || '').split('@')[0].toLowerCase();
const paciente = parts.slice(1).join(' ').trim();
return [{
  json: {
    chat_id: $json.message.chat.id,
    comando,
    paciente
  }
}];

function parseFecha(valor) {
  const [fecha, hora = '00:00:00'] = String(valor || '').split(' ');
  const [d, m, y] = fecha.split('/').map(Number);
  const [hh, mm, ss] = hora.split(':').map(Number);
  return new Date(y, m - 1, d, hh || 0, mm || 0, ss || 0);
}
const rows = $input.all().map(i => i.json);
rows.sort((a, b) => parseFecha(b.Fecha) - parseFecha(a.Fecha));
const r = rows[0];
const chatId = $('Parsear comando').first().json.chat_id;
if (!r) {
  return [{ json: { chat_id: chatId, text: 'No se encontraron sesiones para ese paciente.' } }];
}
const min = Math.round(Number(r.Duracion || 0) / 60);
const text = `Paciente: ${r.Paciente}

Última sesión:

Fecha: ${r.Fecha}
Duración: ${min} min

Dedo 1
ROM:${r.D1_ROM}°
Repeticiones:${r.D1_Reps}

Dedo 2
ROM:${r.D2_ROM}°
Repeticiones:${r.D2_Reps}

Dedo 3
ROM:${r.D3_ROM}°
Repeticiones:${r.D3_Reps}

ROM promedio:
${r.ROM_Promedio}°

Repeticiones totales:
${r.Reps_Totales}

Resumen:
${r.ResumenIA || 'Sin resumen registrado.'}`;
return [{ json: { chat_id: chatId, text } }];

function parseFecha(valor) {
  const [fecha, hora = '00:00:00'] = String(valor || '').split(' ');
  const [d, m, y] = fecha.split('/').map(Number);
  const [hh, mm, ss] = hora.split(':').map(Number);
  return new Date(y, m - 1, d, hh || 0, mm || 0, ss || 0);
}
const rows = $input.all().map(i => i.json);
rows.sort((a, b) => parseFecha(b.Fecha) - parseFecha(a.Fecha));
const recientes = rows.slice(0, 5);
const cronologico = [...recientes].reverse();
const chatId = $('Parsear comando').first().json.chat_id;
const paciente = $('Parsear comando').first().json.paciente;
if (!recientes.length) {
  return [{ json: { chat_id: chatId, text: 'No se encontraron sesiones para ese paciente.' } }];
}
let lineas = [`${paciente} - Historial`, ''];
recientes.forEach((r, idx) => {
  lineas.push(`Sesión ${recientes.length - idx} → ROM promedio ${Math.round(Number(r.ROM_Promedio || 0))}°`);
});
const primera = Number(cronologico[0].ROM_Promedio || 0);
const ultima = Number(cronologico[cronologico.length - 1].ROM_Promedio || 0);
let tendencia = 'Sin cambio claro';
if (ultima > primera) tendencia = 'Mejora progresiva';
if (ultima < primera) tendencia = 'Variación descendente observada';
lineas.push('', 'Tendencia:', tendencia);
return [{ json: { chat_id: chatId, text: lineas.join('\n') } }];
